170→pub fn fix_ochid(args: &FixOchidArgs) -> Result<(), Box<dyn std::error::Error>> {
171→    let (workspace, repo) = common::load_repo(&args.repo)?;
172→    let (other_workspace, other_repo) = common::load_repo(&args.other_repo)?;
173→    let other_prefix = repo_to_ochid_prefix(&args.other_repo);
174→
175→    let spec = common::resolve_spec(
176→        args.pos_rev.as_deref(),
177→        args.pos_count,
178→        &args.revision,
179→        args.limit,
180→        "@",
181→    );
182→
183→    let (ids, _anchor_index) = common::collect_ids(
184→        &workspace,
185→        &repo,
186→        &spec.rev,
187→        spec.desc_count,
188→        spec.anc_count,
189→    )?;
190→    if ids.is_empty() {
191→        return Err(format!("no commits found for revision '{}'", args.revision).into());
192→    }
193→
194→    let root_id = repo.store().root_commit_id().clone();
195→    let mut fixed = 0;
196→    let mut skipped = 0;
197→    let mut errors = 0;
198→
199→    for commit_id in &ids {
200→        if *commit_id == root_id {
201→            continue;
202→        }
203→        let commit = repo.store().get_commit(commit_id)?;
204→        let desc = commit.description();
205→        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
206→        let change_short = &change_hex[..change_hex.len().min(12)];
207→
208→        // Extract current ochid value
209→        let current_ochid = common::extract_ochid(&commit);
210→
211→        // Validate current ochid
212→        let issues = if let Some(ref ochid_val) = current_ochid {
213→            validate_ochid(
214→                ochid_val,
215→                &other_prefix,
216→                args.id_len,
217→                &other_workspace,
218→                &other_repo,
219→            )
220→        } else {
221→            // No ochid trailer — nothing to fix
222→            skipped += 1;
223→            if !args.no_dry_run {
224→                println!("skip {change_short}  (no ochid trailer)");
225→            }
226→            continue;
227→        };
228→
229→        if !issues.any() {
230→            skipped += 1;
231→            if !args.no_dry_run {
232→                println!("ok   {change_short}  (valid)");
233→            }
234→            continue;
235→        }
236→
237→        // Build the fixed description
238→        let mut new_desc =
239→            fix_ochid_in_description(desc, &other_prefix, args.id_len, args.title.as_deref());
240→
241→        // Re-extract the fixed ochid value for post-validation
242→        let mut fixed_ochid = {
243→            let mut val = None;
244→            for line in new_desc.lines() {
245→                let trimmed = line.trim();
246→                if let Some(v) = trimmed.strip_prefix("ochid:") {
247→                    val = Some(v.trim().to_string());
248→                }
249→            }
250→            val
251→        };
252→
253→        let post_issues = if let Some(ref v) = fixed_ochid {
254→            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
255→        } else {
256→            OchidIssues {
257→                wrong_prefix: false,
258→                wrong_length: false,
259→                not_found: true,
260→            }
261→        };
262→
263→        if post_issues.not_found {
264→            if let Some(ref fallback) = args.fallback {
265→                // Replace the ochid line with the fallback value
266→                let mut fb_lines: Vec<String> = new_desc.lines().map(|l| l.to_string()).collect();
267→                for line in &mut fb_lines {
268→                    if line.trim().starts_with("ochid:") {
269→                        *line = format!("ochid: {fallback}");
270→                    }
271→                }
272→                let fb_desc = if new_desc.ends_with('\n') {
273→                    format!("{}\n", fb_lines.join("\n"))
274→                } else {
275→                    fb_lines.join("\n")
276→                };
277→                new_desc = fb_desc;
278→                fixed_ochid = Some(fallback.clone());
279→            } else {
280→                errors += 1;
281→                eprintln!(
282→                    "err  {change_short}  ID not found in other repo (ochid: {})",
283→                    fixed_ochid.as_deref().unwrap_or("?")
284→                );
285→                continue;
286→            }
287→        }
288→
289→        if !args.no_dry_run {
290→            let first_line = new_desc.lines().next().unwrap_or("");
291→            println!("fix  {change_short}  {first_line}  [{}]", issues.summary());
292→            if let Some(ref v) = fixed_ochid {
293→                println!("     -> ochid: {v}");
294→            }
295→        } else {
296→            let status = Command::new("jj")
297→                .arg("describe")
298→                .arg("-m")
299→                .arg(&new_desc)
300→                .arg("-r")
301→                .arg(commit_id.hex())
302→                .arg("-R")
303→                .arg(&args.repo)
304→                .arg("--ignore-immutable")
305→                .stdout(std::process::Stdio::null())
306→                .stderr(std::process::Stdio::inherit())
307→                .status()?;
308→            if !status.success() {
309→                return Err(format!(
310→                    "jj describe failed for {} (exit {})",
311→                    change_short,
312→                    status.code().unwrap_or(-1)
313→                )
314→                .into());
315→            }
316→            let first_line = new_desc.lines().next().unwrap_or("");
317→            println!("fixed {change_short}  {first_line}");
318→        }
319→        fixed += 1;
320→    }
321→
322→    println!(
323→        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
324→        ids.len()
325→    );
326→    if errors > 0 {
327→        Err(format!("{errors} commit(s) could not be fixed").into())
328→    } else {
329→        Ok(())
330→    }
331→}
