}

impl OchidIssues {
    fn any(&self) -> bool {
        self.wrong_prefix || self.wrong_length || self.not_found
    }

    fn summary(&self) -> String {
        let mut parts = Vec::new();
        if self.wrong_prefix {
            parts.push("wrong prefix");
        }
