187→    let (other_workspace, other_repo) = common::load_repo(&args.other_repo)?;
188→    let other_config = toml_simple::toml_load(&args.other_repo.join(VC_CONFIG_FILE))?;
189→    let other_prefix = ochid_prefix_from_config(&other_config)?;
190→
191→    let spec = common::resolve_spec(
192→        args.pos_rev.as_deref(),
193→        args.pos_count,
194→        &args.revision,
195→        args.limit,
196→        "@",
197→    );
198→
199→    let (ids, _anchor_index) = common::collect_ids(
200→        &workspace,
201→        &repo,
202→        &spec.rev,
203→        spec.desc_count,
204→        spec.anc_count,
205→    )?;
206→    if ids.is_empty() {
207→        return Err(format!("no commits found for revision '{}'", args.revision).into());
208→    }
209→
210→    let root_id = repo.store().root_commit_id().clone();
211→    let mut fixed = 0;
212→    let mut skipped = 0;
213→    let mut errors = 0;
214→
215→    for commit_id in &ids {
216→        if *commit_id == root_id {
217→            continue;
218→        }
219→        let commit = repo.store().get_commit(commit_id)?;
220→        let desc = commit.description();
221→        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
222→        let change_short = &change_hex[..change_hex.len().min(12)];
223→
224→        // Extract current ochid value
225→        let current_ochid = common::extract_ochid(&commit);
226→
227→        // Validate current ochid
228→        let issues = if let Some(ref ochid_val) = current_ochid {
229→            validate_ochid(
230→                ochid_val,
231→                &other_prefix,
232→                args.id_len,
233→                &other_workspace,
234→                &other_repo,
235→            )
236→        } else {
237→            // No ochid trailer — nothing to fix
238→            skipped += 1;
239→            if !args.no_dry_run {
240→                println!("skip {change_short}  (no ochid trailer)");
241→            }
242→            continue;
243→        };
244→
245→        if !issues.any() {
246→            skipped += 1;
247→            if !args.no_dry_run {
248→                println!("ok   {change_short}  (valid)");
249→            }
250→            continue;
251→        }
252→
253→        // Resolve the full change ID from the other repo when length is wrong
254→        let resolved_id = if issues.wrong_length {
255→            let ochid_val = current_ochid.as_deref().unwrap_or("");
256→            let bare_id = if let Some(pos) = ochid_val.rfind('/') {
257→                &ochid_val[pos + 1..]
258→            } else {
259→                ochid_val
260→            };
261→            if let Ok(commit_ids) = common::resolve_revset(&other_workspace, &other_repo, bare_id)
262→                && let Some(cid) = commit_ids.first()
263→            {
264→                let other_commit = other_repo.store().get_commit(cid)?;
265→                let full_hex =
266→                    jj_lib::hex_util::encode_reverse_hex(other_commit.change_id().as_bytes());
267→                Some(full_hex)
268→            } else {
269→                None
270→            }
271→        } else {
272→            None
273→        };
274→
275→        // Build the fixed description
276→        let mut new_desc = fix_ochid_in_description(
277→            desc,
278→            &other_prefix,
279→            args.id_len,
280→            args.title.as_deref(),
281→            resolved_id.as_deref(),
282→        );
283→
284→        // Re-extract the fixed ochid value for post-validation
285→        let mut fixed_ochid = {
286→            let mut val = None;
287→            for line in new_desc.lines() {
288→                let trimmed = line.trim();
289→                if let Some(v) = trimmed.strip_prefix("ochid:") {
290→                    val = Some(v.trim().to_string());
291→                }
292→            }
293→            val
294→        };
295→
296→        let post_issues = if let Some(ref v) = fixed_ochid {
297→            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
298→        } else {
299→            OchidIssues {
300→                wrong_prefix: false,
301→                wrong_length: false,
302→                not_found: true,
303→            }
304→        };
305→
306→        if post_issues.not_found {
307→            if let Some(ref fallback) = args.fallback {
308→                // Replace the ochid line with the fallback value
309→                let mut fb_lines: Vec<String> = new_desc.lines().map(|l| l.to_string()).collect();
310→                for line in &mut fb_lines {
311→                    if line.trim().starts_with("ochid:") {
312→                        *line = format!("ochid: {fallback}");
313→                    }
314→                }
315→                let fb_desc = if new_desc.ends_with('\n') {
316→                    format!("{}\n", fb_lines.join("\n"))
317→                } else {
318→                    fb_lines.join("\n")
319→                };
320→                new_desc = fb_desc;
321→                fixed_ochid = Some(fallback.clone());
322→            } else {
323→                errors += 1;
324→                eprintln!(
325→                    "err  {change_short}  ID not found in other repo (ochid: {})",
326→                    fixed_ochid.as_deref().unwrap_or("?")
327→                );
328→                continue;
329→            }
330→        }
331→
332→        if !args.no_dry_run {
333→            let first_line = new_desc.lines().next().unwrap_or("");
334→            println!("fix  {change_short}  {first_line}  [{}]", issues.summary());
335→            if let Some(ref v) = fixed_ochid {
336→                println!("     -> ochid: {v}");
337→            }
338→        } else {
339→            let status = Command::new("jj")
340→                .arg("describe")
341→                .arg("-m")
342→                .arg(&new_desc)
343→                .arg("-r")
344→                .arg(commit_id.hex())
345→                .arg("-R")
346→                .arg(&args.repo)
347→                .arg("--ignore-immutable")
348→                .stdout(std::process::Stdio::null())
349→                .stderr(std::process::Stdio::inherit())
350→                .status()?;
351→            if !status.success() {
352→                return Err(format!(
353→                    "jj describe failed for {} (exit {})",
354→                    change_short,
355→                    status.code().unwrap_or(-1)
356→                )
357→                .into());
358→            }
359→            let first_line = new_desc.lines().next().unwrap_or("");
360→            println!("fixed {change_short}  {first_line}");
361→        }
362→        fixed += 1;
363→    }
364→
365→    println!(
366→        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
367→        ids.len()
368→    );
369→    if errors > 0 {
370→        Err(format!("{errors} commit(s) could not be fixed").into())
371→    } else {
372→        Ok(())
373→    }
374→}
