            let first_line = new_desc.lines().next().unwrap_or("");
            println!("fixed {change_short}  {first_line}");
        }
        fixed += 1;
    }

    println!(
        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
        ids.len()
    );
    if errors > 0 {
        Err(format!("{errors} commit(s) could not be fixed").into())
    } else {
        Ok(())
    }
}

