 67→/// Derive the ochid prefix from the other repo's `.vc-config.toml`.
 68→///
 69→/// The `workspace.path` value is the repo's path relative to the workspace
 70→/// root, which is exactly the ochid prefix (with a trailing `/` when the
 71→/// path isn't just `/`).
 72→fn ochid_prefix_from_config(
 73→    config: &std::collections::HashMap<String, String>,
 74→) -> Result<String, Box<dyn std::error::Error>> {
 75→    let ws_path = toml_simple::toml_get(config, "workspace.path")
 76→        .ok_or("missing workspace.path in .vc-config.toml")?;
 77→    let trimmed = ws_path.trim_end_matches('/');
 78→    if trimmed.is_empty() {
 79→        Ok("/".to_string())
 80→    } else {
 81→        Ok(format!("{trimmed}/"))
 82→    }
 83→}
 84→
 85→/// Problems found with an ochid trailer.
 86→#[derive(Debug)]
 87→struct OchidIssues {
 88→    wrong_prefix: bool,
 89→    wrong_length: bool,
 90→    not_found: bool,
 91→}
 92→
 93→impl OchidIssues {
 94→    fn any(&self) -> bool {
 95→        self.wrong_prefix || self.wrong_length || self.not_found
 96→    }
 97→
 98→    fn summary(&self) -> String {
 99→        let mut parts = Vec::new();
100→        if self.wrong_prefix {
101→            parts.push("wrong prefix");
102→        }
103→        if self.wrong_length {
104→            parts.push("wrong ID length");
105→        }
106→        if self.not_found {
107→            parts.push("ID not found in other repo");
108→        }
109→        parts.join(", ")
110→    }
111→}
112→
113→/// Validate an ochid trailer value against expected prefix, length, and other repo.
114→fn validate_ochid(
115→    value: &str,
116→    other_prefix: &str,
117→    id_len: usize,
118→    other_workspace: &Workspace,
119→    other_repo: &Arc<ReadonlyRepo>,
120→) -> OchidIssues {
121→    let wrong_prefix = !value.starts_with(other_prefix);
122→
123→    // Extract the bare ID
124→    let bare_id = if let Some(pos) = value.rfind('/') {
125→        &value[pos + 1..]
126→    } else {
127→        value
128→    };
129→
130→    let wrong_length = bare_id.len() != id_len;
131→
132→    // Check if the ID resolves in the other repo
133→    let not_found = common::resolve_revset(other_workspace, other_repo, bare_id)
134→        .map(|ids| ids.is_empty())
135→        .unwrap_or(true);
136→
137→    OchidIssues {
138→        wrong_prefix,
139→        wrong_length,
140→        not_found,
141→    }
142→}
143→
144→/// Fix the ochid trailer in a commit description.
145→///
146→/// If `resolved_id` is provided, it replaces the bare changeID entirely
147→/// (used when the existing ID is too short to extend by truncation alone).
148→fn fix_ochid_in_description(
149→    desc: &str,
150→    other_prefix: &str,
151→    id_len: usize,
152→    new_title: Option<&str>,
153→    resolved_id: Option<&str>,
154→) -> String {
155→    let mut lines: Vec<String> = desc.lines().map(|l| l.to_string()).collect();
156→
157→    // Fix title if requested
158→    if let Some(title) = new_title
159→        && !lines.is_empty()
160→    {
161→        lines[0] = title.to_string();
162→    }
163→
164→    // Fix ochid trailer
165→    for line in &mut lines {
166→        let trimmed = line.trim();
167→        if let Some(value) = trimmed.strip_prefix("ochid:") {
168→            let value = value.trim();
169→            let id = if let Some(rid) = resolved_id {
170→                &rid[..rid.len().min(id_len)]
171→            } else {
172→                // Extract the bare changeID (strip any existing path prefix)
173→                let bare_id = if let Some(pos) = value.rfind('/') {
174→                    &value[pos + 1..]
175→                } else {
176→                    value
177→                };
178→                // Normalize to id_len chars
179→                &bare_id[..bare_id.len().min(id_len)]
180→            };
181→            *line = format!("ochid: {other_prefix}{id}");
182→        }
183→    }
184→
185→    // Preserve trailing newline if original had one
186→    let mut result = lines.join("\n");
187→    if desc.ends_with('\n') {
188→        result.push('\n');
189→    }
190→    result
191→}
192→
193→/// Maximum timestamp difference (in milliseconds) for title-based matching.
194→const TIMESTAMP_TOLERANCE_MS: i64 = 60_000;
195→
196→/// Find a unique matching commit in the other repo by title and timestamp.
197→///
198→/// Returns the other commit's change ID (full hex) if exactly one commit
199→/// in the other repo has the same first description line and a committer
200→/// timestamp within `TIMESTAMP_TOLERANCE_MS` of the source commit.
201→fn find_matching_commit(
202→    commit: &jj_lib::commit::Commit,
203→    other_workspace: &Workspace,
204→    other_repo: &Arc<ReadonlyRepo>,
205→) -> Result<Option<String>, Box<dyn std::error::Error>> {
206→    let title = commit.description().lines().next().unwrap_or("");
207→    if title.is_empty() {
208→        return Ok(None);
209→    }
210→    let src_millis = commit.committer().timestamp.timestamp.0;
211→
212→    // Search all commits in the other repo
213→    let all_ids = common::resolve_revset(other_workspace, other_repo, "all()")?;
214→    let root_id = other_repo.store().root_commit_id().clone();
215→
216→    let mut matches = Vec::new();
217→    for cid in &all_ids {
218→        if *cid == root_id {
219→            continue;
220→        }
221→        let other_commit = other_repo.store().get_commit(cid)?;
222→        let other_title = other_commit.description().lines().next().unwrap_or("");
223→        if other_title != title {
224→            continue;
225→        }
226→        let other_millis = other_commit.committer().timestamp.timestamp.0;
227→        if (src_millis - other_millis).abs() <= TIMESTAMP_TOLERANCE_MS {
228→            let full_hex =
229→                jj_lib::hex_util::encode_reverse_hex(other_commit.change_id().as_bytes());
230→            matches.push(full_hex);
231→        }
232→    }
233→
234→    if matches.len() == 1 {
235→        Ok(Some(matches.into_iter().next().unwrap()))
236→    } else {
237→        Ok(None)
238→    }
239→}
240→
241→/// Append an ochid trailer to a commit description.
242→fn append_ochid_trailer(desc: &str, other_prefix: &str, change_id: &str, id_len: usize) -> String {
243→    let short_id = &change_id[..change_id.len().min(id_len)];
244→    let trailer = format!("ochid: {other_prefix}{short_id}");
245→
246→    let mut result = desc.trim_end().to_string();
247→    // Add blank line before trailer if body exists, otherwise just newline
248→    if result.lines().count() > 1 {
249→        result.push('\n');
250→    } else {
251→        result.push_str("\n\n");
252→    }
253→    result.push_str(&trailer);
254→    result.push('\n');
255→    result
256→}
