    } else {
        Ok(None)
    }
}

/// Extract the bare change ID from an ochid value (strip path prefix).
pub fn extract_bare_id(ochid_value: &str) -> &str {
    if let Some(pos) = ochid_value.rfind('/') {
        &ochid_value[pos + 1..]
    } else {
        ochid_value
    }
}

