  1→use std::path::PathBuf;
  2→use std::process::Command;
  3→use std::sync::Arc;
  4→
  5→use clap::Args;
  6→use jj_lib::object_id::ObjectId;
  7→use jj_lib::repo::{ReadonlyRepo, Repo};
  8→use jj_lib::workspace::Workspace;
  9→
 10→use crate::common;
 11→use crate::toml_simple;
 12→
 13→const DEFAULT_ID_LEN: usize = 12;
 14→const VC_CONFIG_FILE: &str = ".vc-config.toml";
 15→
 16→#[derive(Args, Debug)]
 17→pub struct FixOchidArgs {
 18→    /// Revision (with optional .. notation)
 19→    #[arg(value_name = "REVISION")]
 20→    pub pos_rev: Option<String>,
 21→
 22→    /// Number of commits (per dotted side)
 23→    #[arg(value_name = "COMMITS")]
 24→    pub pos_count: Option<usize>,
 25→
 26→    /// Revision(s) to scan
 27→    #[arg(short, long, default_value = "@")]
 28→    pub revision: String,
 29→
 30→    /// Number of commits to scan
 31→    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
 32→    pub limit: Option<usize>,
 33→
 34→    /// Maximum number of commits to actually fix/change [default: all]
 35→    #[arg(short = 'm', long = "max-fixes")]
 36→    pub max_fixes: Option<usize>,
 37→
 38→    /// Path to jj repo
 39→    #[arg(short = 'R', long, default_value = ".")]
 40→    pub repo: PathBuf,
 41→
 42→    /// Path to the other repo (e.g. .claude or .)
 43→    #[arg(long = "other-repo")]
 44→    pub other_repo: PathBuf,
 45→
 46→    /// Expected changeID length
 47→    #[arg(long = "id-len", default_value_t = DEFAULT_ID_LEN)]
 48→    pub id_len: usize,
 49→
 50→    /// New title to replace the first line (optional)
 51→    #[arg(long)]
 52→    pub title: Option<String>,
 53→
 54→    /// Fallback ochid value for IDs not found in other repo (e.g. /.claude/lost)
 55→    #[arg(long)]
 56→    pub fallback: Option<String>,
 57→
 58→    /// Actually write changes (default is dry-run)
 59→    #[arg(long = "no-dry-run")]
 60→    pub no_dry_run: bool,
 61→
 62→    /// Add missing ochid trailers by matching title and timestamp
 63→    #[arg(long = "add-missing")]
 64→    pub add_missing: bool,
 65→}
 66→
 67→/// Derive the ochid prefix from the other repo's `.vc-config.toml`.
 68→///
 69→/// The `workspace.path` value is the repo's path relative to the workspace
 70→/// root, which is exactly the ochid prefix (with a trailing `/` when the
 71→/// path isn't just `/`).
 72→fn ochid_prefix_from_config(
 73→    config: &std::collections::HashMap<String, String>,
 74→) -> Result<String, Box<dyn std::error::Error>> {
 75→    let ws_path = toml_simple::toml_get(config, "workspace.path")
 76→        .ok_or("missing workspace.path in .vc-config.toml")?;
 77→    let trimmed = ws_path.trim_end_matches('/');
 78→    if trimmed.is_empty() {
 79→        Ok("/".to_string())
 80→    } else {
 81→        Ok(format!("{trimmed}/"))
 82→    }
 83→}
 84→
 85→/// Problems found with an ochid trailer.
 86→#[derive(Debug)]
 87→struct OchidIssues {
 88→    wrong_prefix: bool,
 89→    wrong_length: bool,
 90→    not_found: bool,
 91→}
 92→
 93→impl OchidIssues {
 94→    fn any(&self) -> bool {
 95→        self.wrong_prefix || self.wrong_length || self.not_found
 96→    }
 97→
 98→    fn summary(&self) -> String {
 99→        let mut parts = Vec::new();
100→        if self.wrong_prefix {
101→            parts.push("wrong prefix");
102→        }
103→        if self.wrong_length {
104→            parts.push("wrong ID length");
105→        }
106→        if self.not_found {
107→            parts.push("ID not found in other repo");
108→        }
109→        parts.join(", ")
110→    }
111→}
112→
113→/// Validate an ochid trailer value against expected prefix, length, and other repo.
114→fn validate_ochid(
115→    value: &str,
116→    other_prefix: &str,
117→    id_len: usize,
118→    other_workspace: &Workspace,
119→    other_repo: &Arc<ReadonlyRepo>,
120→) -> OchidIssues {
121→    let wrong_prefix = !value.starts_with(other_prefix);
122→
123→    // Extract the bare ID
124→    let bare_id = if let Some(pos) = value.rfind('/') {
125→        &value[pos + 1..]
126→    } else {
127→        value
128→    };
129→
130→    let wrong_length = bare_id.len() != id_len;
131→
132→    // Check if the ID resolves in the other repo
133→    let not_found = common::resolve_revset(other_workspace, other_repo, bare_id)
134→        .map(|ids| ids.is_empty())
135→        .unwrap_or(true);
136→
137→    OchidIssues {
138→        wrong_prefix,
139→        wrong_length,
140→        not_found,
141→    }
142→}
143→
144→/// Fix the ochid trailer in a commit description.
145→///
146→/// If `resolved_id` is provided, it replaces the bare changeID entirely
147→/// (used when the existing ID is too short to extend by truncation alone).
148→fn fix_ochid_in_description(
149→    desc: &str,
150→    other_prefix: &str,
151→    id_len: usize,
152→    new_title: Option<&str>,
153→    resolved_id: Option<&str>,
154→) -> String {
155→    let mut lines: Vec<String> = desc.lines().map(|l| l.to_string()).collect();
156→
157→    // Fix title if requested
158→    if let Some(title) = new_title
159→        && !lines.is_empty()
160→    {
161→        lines[0] = title.to_string();
162→    }
163→
164→    // Fix ochid trailer
165→    for line in &mut lines {
166→        let trimmed = line.trim();
167→        if let Some(value) = trimmed.strip_prefix("ochid:") {
168→            let value = value.trim();
169→            let id = if let Some(rid) = resolved_id {
170→                &rid[..rid.len().min(id_len)]
171→            } else {
172→                // Extract the bare changeID (strip any existing path prefix)
173→                let bare_id = if let Some(pos) = value.rfind('/') {
174→                    &value[pos + 1..]
175→                } else {
176→                    value
177→                };
178→                // Normalize to id_len chars
179→                &bare_id[..bare_id.len().min(id_len)]
180→            };
181→            *line = format!("ochid: {other_prefix}{id}");
182→        }
183→    }
184→
185→    // Preserve trailing newline if original had one
186→    let mut result = lines.join("\n");
187→    if desc.ends_with('\n') {
188→        result.push('\n');
189→    }
190→    result
191→}
192→
193→/// Maximum timestamp difference (in milliseconds) for title-based matching.
194→const TIMESTAMP_TOLERANCE_MS: i64 = 60_000;
195→
196→/// Find a unique matching commit in the other repo by title and timestamp.
197→///
198→/// Returns the other commit's change ID (full hex) if exactly one commit
199→/// in the other repo has the same first description line and a committer
200→/// timestamp within `TIMESTAMP_TOLERANCE_MS` of the source commit.
201→fn find_matching_commit(
202→    commit: &jj_lib::commit::Commit,
203→    other_workspace: &Workspace,
204→    other_repo: &Arc<ReadonlyRepo>,
205→) -> Result<Option<String>, Box<dyn std::error::Error>> {
206→    let title = commit.description().lines().next().unwrap_or("");
207→    if title.is_empty() {
208→        return Ok(None);
209→    }
210→    let src_millis = commit.committer().timestamp.timestamp.0;
211→
212→    // Search all commits in the other repo
213→    let all_ids = common::resolve_revset(other_workspace, other_repo, "all()")?;
214→    let root_id = other_repo.store().root_commit_id().clone();
215→
216→    let mut matches = Vec::new();
217→    for cid in &all_ids {
218→        if *cid == root_id {
219→            continue;
220→        }
221→        let other_commit = other_repo.store().get_commit(cid)?;
222→        let other_title = other_commit.description().lines().next().unwrap_or("");
223→        if other_title != title {
224→            continue;
225→        }
226→        let other_millis = other_commit.committer().timestamp.timestamp.0;
227→        if (src_millis - other_millis).abs() <= TIMESTAMP_TOLERANCE_MS {
228→            let full_hex =
229→                jj_lib::hex_util::encode_reverse_hex(other_commit.change_id().as_bytes());
230→            matches.push(full_hex);
231→        }
232→    }
233→
234→    if matches.len() == 1 {
235→        Ok(Some(matches.into_iter().next().unwrap()))
236→    } else {
237→        Ok(None)
238→    }
239→}
240→
241→/// Append an ochid trailer to a commit description.
242→fn append_ochid_trailer(desc: &str, other_prefix: &str, change_id: &str, id_len: usize) -> String {
243→    let short_id = &change_id[..change_id.len().min(id_len)];
244→    let trailer = format!("ochid: {other_prefix}{short_id}");
245→
246→    let mut result = desc.trim_end().to_string();
247→    // Add blank line before trailer if body exists, otherwise just newline
248→    if result.lines().count() > 1 {
249→        result.push('\n');
250→    } else {
251→        result.push_str("\n\n");
252→    }
253→    result.push_str(&trailer);
254→    result.push('\n');
255→    result
256→}
257→
258→pub fn fix_ochid(args: &FixOchidArgs) -> Result<(), Box<dyn std::error::Error>> {
259→    let (workspace, repo) = common::load_repo(&args.repo)?;
260→    let (other_workspace, other_repo) = common::load_repo(&args.other_repo)?;
261→    let other_config = toml_simple::toml_load(&args.other_repo.join(VC_CONFIG_FILE))?;
262→    let other_prefix = ochid_prefix_from_config(&other_config)?;
263→
264→    let spec = common::resolve_spec(
265→        args.pos_rev.as_deref(),
266→        args.pos_count,
267→        &args.revision,
268→        args.limit,
269→        "@",
270→    );
271→
272→    let (ids, _anchor_index) = common::collect_ids(
273→        &workspace,
274→        &repo,
275→        &spec.rev,
276→        spec.desc_count,
277→        spec.anc_count,
278→    )?;
279→    if ids.is_empty() {
280→        return Err(format!("no commits found for revision '{}'", args.revision).into());
281→    }
282→
283→    let root_id = repo.store().root_commit_id().clone();
284→    let mut fixed = 0;
285→    let mut skipped = 0;
286→    let mut errors = 0;
287→
288→    for commit_id in &ids {
289→        if *commit_id == root_id {
290→            continue;
291→        }
292→        let commit = repo.store().get_commit(commit_id)?;
293→        let desc = commit.description();
294→        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
295→        let change_short = &change_hex[..change_hex.len().min(12)];
296→
297→        // Extract current ochid value
298→        let current_ochid = common::extract_ochid(&commit);
299→
300→        // Validate current ochid
301→        let issues = if let Some(ref ochid_val) = current_ochid {
302→            validate_ochid(
303→                ochid_val,
304→                &other_prefix,
305→                args.id_len,
306→                &other_workspace,
307→                &other_repo,
308→            )
309→        } else if args.add_missing {
310→            // Stop if we've hit the max-fixes limit
311→            if let Some(max) = args.max_fixes
312→                && fixed >= max
313→            {
314→                skipped += 1;
315→                if !args.no_dry_run {
316→                    println!("skip {change_short}  (max-fixes reached)");
317→                }
318→                continue;
319→            }
320→            // No ochid trailer — try to infer from the other repo
321→            if let Some(matched_id) = find_matching_commit(&commit, &other_workspace, &other_repo)?
322→            {
323→                let new_desc = append_ochid_trailer(desc, &other_prefix, &matched_id, args.id_len);
324→                let first_line = desc.lines().next().unwrap_or("");
325→                let short_matched = &matched_id[..matched_id.len().min(args.id_len)];
326→                if !args.no_dry_run {
327→                    println!("add  {change_short}  {first_line}  [missing]");
328→                    println!("     -> ochid: {other_prefix}{short_matched}");
329→                } else {
330→                    let status = Command::new("jj")
331→                        .arg("describe")
332→                        .arg("-m")
333→                        .arg(&new_desc)
334→                        .arg("-r")
335→                        .arg(commit_id.hex())
336→                        .arg("-R")
337→                        .arg(&args.repo)
338→                        .arg("--ignore-immutable")
339→                        .stdout(std::process::Stdio::null())
340→                        .stderr(std::process::Stdio::inherit())
341→                        .status()?;
342→                    if !status.success() {
343→                        return Err(format!(
344→                            "jj describe failed for {} (exit {})",
345→                            change_short,
346→                            status.code().unwrap_or(-1)
347→                        )
348→                        .into());
349→                    }
350→                    println!("added {change_short}  {first_line}");
351→                }
352→                fixed += 1;
353→                continue;
354→            } else {
355→                skipped += 1;
356→                if !args.no_dry_run {
357→                    println!("skip {change_short}  (no ochid, no match in other repo)");
358→                }
359→                continue;
360→            }
361→        } else {
362→            // No ochid trailer — nothing to fix
363→            skipped += 1;
364→            if !args.no_dry_run {
365→                println!("skip {change_short}  (no ochid trailer)");
366→            }
367→            continue;
368→        };
369→
370→        if !issues.any() {
371→            skipped += 1;
372→            if !args.no_dry_run {
373→                println!("ok   {change_short}  (valid)");
374→            }
375→            continue;
376→        }
377→
378→        // Stop if we've hit the max-fixes limit
379→        if let Some(max) = args.max_fixes
380→            && fixed >= max
381→        {
382→            skipped += 1;
383→            if !args.no_dry_run {
384→                println!("skip {change_short}  (max-fixes reached)");
385→            }
386→            continue;
387→        }
388→
389→        // Resolve the full change ID from the other repo when length is wrong
390→        let resolved_id = if issues.wrong_length {
391→            let ochid_val = current_ochid.as_deref().unwrap_or("");
392→            let bare_id = if let Some(pos) = ochid_val.rfind('/') {
393→                &ochid_val[pos + 1..]
394→            } else {
395→                ochid_val
396→            };
397→            if let Ok(commit_ids) = common::resolve_revset(&other_workspace, &other_repo, bare_id)
398→                && let Some(cid) = commit_ids.first()
399→            {
400→                let other_commit = other_repo.store().get_commit(cid)?;
401→                let full_hex =
402→                    jj_lib::hex_util::encode_reverse_hex(other_commit.change_id().as_bytes());
403→                Some(full_hex)
404→            } else {
405→                None
406→            }
407→        } else {
408→            None
409→        };
410→
411→        // Build the fixed description
412→        let mut new_desc = fix_ochid_in_description(
413→            desc,
414→            &other_prefix,
415→            args.id_len,
416→            args.title.as_deref(),
417→            resolved_id.as_deref(),
418→        );
419→
420→        // Re-extract the fixed ochid value for post-validation
421→        let mut fixed_ochid = {
422→            let mut val = None;
423→            for line in new_desc.lines() {
424→                let trimmed = line.trim();
425→                if let Some(v) = trimmed.strip_prefix("ochid:") {
426→                    val = Some(v.trim().to_string());
427→                }
428→            }
429→            val
430→        };
431→
432→        let post_issues = if let Some(ref v) = fixed_ochid {
433→            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
434→        } else {
435→            OchidIssues {
436→                wrong_prefix: false,
437→                wrong_length: false,
438→                not_found: true,
439→            }
440→        };
441→
442→        if post_issues.not_found {
443→            if let Some(ref fallback) = args.fallback {
444→                // Replace the ochid line with the fallback value
445→                let mut fb_lines: Vec<String> = new_desc.lines().map(|l| l.to_string()).collect();
446→                for line in &mut fb_lines {
447→                    if line.trim().starts_with("ochid:") {
448→                        *line = format!("ochid: {fallback}");
449→                    }
450→                }
451→                let fb_desc = if new_desc.ends_with('\n') {
452→                    format!("{}\n", fb_lines.join("\n"))
453→                } else {
454→                    fb_lines.join("\n")
455→                };
456→                new_desc = fb_desc;
457→                fixed_ochid = Some(fallback.clone());
458→            } else {
459→                errors += 1;
460→                eprintln!(
461→                    "err  {change_short}  ID not found in other repo (ochid: {})",
462→                    fixed_ochid.as_deref().unwrap_or("?")
463→                );
464→                continue;
465→            }
466→        }
467→
468→        if !args.no_dry_run {
469→            let first_line = new_desc.lines().next().unwrap_or("");
470→            println!("fix  {change_short}  {first_line}  [{}]", issues.summary());
471→            if let Some(ref v) = fixed_ochid {
472→                println!("     -> ochid: {v}");
473→            }
474→        } else {
475→            let status = Command::new("jj")
476→                .arg("describe")
477→                .arg("-m")
478→                .arg(&new_desc)
479→                .arg("-r")
480→                .arg(commit_id.hex())
481→                .arg("-R")
482→                .arg(&args.repo)
483→                .arg("--ignore-immutable")
484→                .stdout(std::process::Stdio::null())
485→                .stderr(std::process::Stdio::inherit())
486→                .status()?;
487→            if !status.success() {
488→                return Err(format!(
489→                    "jj describe failed for {} (exit {})",
490→                    change_short,
491→                    status.code().unwrap_or(-1)
492→                )
493→                .into());
494→            }
495→            let first_line = new_desc.lines().next().unwrap_or("");
496→            println!("fixed {change_short}  {first_line}");
497→        }
498→        fixed += 1;
499→    }
500→
501→    println!(
502→        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
503→        ids.len()
504→    );
505→    if errors > 0 {
506→        Err(format!("{errors} commit(s) could not be fixed").into())
507→    } else {
508→        Ok(())
509→    }
510→}
